  <svg viewBox="0 0 700 460" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="32" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">El Acuerdo Mirae Asset-Korbit, en Cifras</text>
    <g font-family="sans-serif" font-size="14">
      <text x="20" y="70" fill="#a1a1aa">Participación adquirida</text><text x="680" y="70" fill="#e4e4e7" font-weight="700" text-anchor="end">92,06%</text>
